 1	import {
 2	  HorizontalNav,
 3	  useK8sWatchResource,
 4	} from "@openshift-console/dynamic-plugin-sdk";
 5	import Modals from "components/modals/Modals";
 6	import { ModalsContextProvider } from "components/modals/ModalsContext";
 7	import { nodeHealthCheckKind } from "data/model";
 8	import { NodeHealthCheck } from "data/types";
 9	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
10	import * as React from "react";
11	import NodeHealthCheckDetailsHeading from "./NodeHealthCheckDetailsHeading";
12	import NodeHealthCheckDetailsTab from "./detailsTab/NodeHealthCheckDetailsTab";
13	import NodeHealthCheckYAMLTab from "./NodeHealthCheckYamlTab";
14	import { useNodeHealthCheckNavigation } from "navigation/useNodeHealthCheckNavigation";
15	import { withFallback } from "copiedFromConsole/error";
16	import { StatusBox } from "copiedFromConsole/utils/status-box";
17	import { PageSection } from "@patternfly/react-core";
18	
19	export const useNodeHealthCheckTabs = () => {
20	  const { t } = useNodeHealthCheckTranslation();
21	
22	  const tabs = React.useMemo(
23	    () => [
24	      {
25	        href: "",
26	        name: t("Details"),
27	        component: NodeHealthCheckDetailsTab,
28	      },
29	      {
30	        href: "yaml",
31	        name: t("YAML"),
32	        component: NodeHealthCheckYAMLTab,
33	      },
34	    ],
35	    [t]
36	  );
37	
38	  return tabs;
39	};
40	
41	const NodeHealthCheckDetailsPage_ = ({ name }: { name: string }) => {
42	  const navigation = useNodeHealthCheckNavigation();
43	  const [nodeHealthCheck, loaded, loadError] =
44	    useK8sWatchResource<NodeHealthCheck>({
45	      groupVersionKind: nodeHealthCheckKind,
46	      name,
47	    });
48	  const tabs = useNodeHealthCheckTabs();
49	  return (
50	    <StatusBox loadError={loadError} data={nodeHealthCheck} loaded={loaded}>
51	      <ModalsContextProvider>
52	        <PageSection variant="light">
53	          <NodeHealthCheckDetailsHeading nodeHealthCheck={nodeHealthCheck} />
54	        </PageSection>
55	        <HorizontalNav pages={tabs} resource={nodeHealthCheck} />
56	        <Modals onDelete={() => navigation.gotoList()} />
57	      </ModalsContextProvider>
58	    </StatusBox>
59	  );
60	};
61	
62	const NodeHealthCheckDetailsPage = withFallback(NodeHealthCheckDetailsPage_);
63	
64	export default NodeHealthCheckDetailsPage;

